            for(var j=0;j<response.message.length;j++)
            {

                $.each(frm.doc.expenses || [], function (i, d) {
                if(d.expense_type === "Outstation Expenses"){
                tot += response.message[j].total_amount;
                frappe.model.set_value(d.doctype, d.name, 'amount', tot);
                frappe.model.set_value(d.doctype, d.name, 'sanctioned_amount', tot);
                }
                // if(d.expense_type === "Hotel"){
                // htot += response.message[j].total_hotel_expenses;
                // frappe.model.set_value(d.doctype, d.name, 'amount', htot);
                // frappe.model.set_value(d.doctype, d.name, 'sanctioned_amount', htot);

                // }
                // if(d.expense_type === "Auto Travel"){

                // attot += response.message[j].total_auto_travel_or_others_expenses_amount;

                // frappe.model.set_value(d.doctype, d.name, 'amount', attot);
                // frappe.model.set_value(d.doctype, d.name, 'sanctioned_amount', attot);

                // }
                //  if(d.expense_type === "Others"){

                // ottot += response.message[j].total_others_expenses;

                // frappe.model.set_value(d.doctype, d.name, 'amount', ottot);
                // frappe.model.set_value(d.doctype, d.name, 'sanctioned_amount', ottot);

                // }
                // if(d.expense_type === "Travel"){

                // ttot += response.message[j].total_travel_entry_amount;
                // withallowance += ttot +  response.message[j].total_lunch_allowance;

                // frappe.model.set_value(d.doctype, d.name, 'amount', withallowance);
                // frappe.model.set_value(d.doctype, d.name, 'sanctioned_amount', withallowance);

                // }
                //  if(d.expense_type === "Food"){

                // ftot += response.message[j].total_food_expenses_entry;

