function get_expense_type(frm){
      //cur_frm.clear_table("spokes_function_inspection");
    frappe.call({
    "method": "frappe.client.get_list",
    "args": {
        "doctype": "Expense Claim Type",
        'fields': ['name'],
        filters:{active: 1},
        order_by: 'order_no'
        //'limit_start':0,
        //'limit_page_length': 1000
    } ,
       "callback": function(response) {


            cur_frm.clear_table("expenses");
            for(var i=0;i<response.message.length;i++)
            {
            var child = cur_frm.add_child('expenses');  
                  frappe.model.set_value(child.doctype, child.name, 'expense_date',frm.doc.posting_date);
                  frappe.model.set_value(child.doctype, child.name, 'expense_type',response.message[i].name);
                  frappe.model.set_value(child.doctype, child.name, 'amount',0);

                  //frm.refresh();
                  cur_frm.refresh_fields("expenses");
                   console.log(cur_frm);
            }
                }

        		  });
    }



