frappe.ui.form.on('Expense Claim', {
    employee: function(frm) {
        console.log(frm);

          if(frm.doc.employee)
         {

          cur_frm.clear_table("car_emi_detail");
          cur_frm.clear_table("vehicle_service_format_detail");

        frappe.call({
            method: "frappe.client.get",
                    "args": {
                        "doctype": "Employee",
                        filters: { "name": frm.doc.employee }
                    },
                    callback: function (rr) {
                        var sinv = rr.message;
                        //frm.set_value("lunch_allowance", rr.message.lunch_allowance);


                    var child = cur_frm.add_child('car_emi_detail');

                    frappe.model.set_value(child.doctype,child.name, 'vehicle_no', rr.message.vehicle_number);
                    frappe.model.set_value(child.doctype,child.name, 'amount', rr.message.car_emi);   

                    //   var child1 = cur_frm.add_child('vehicle_service_format_detail');  

                        // frappe.model.set_value(child1.doctype,child1.name, 'vehicle_registration_number', rr.message.vehicle_reg_no);

                        // cur_frm.refresh_fields("vehicle_service_format_detail");

                        cur_frm.refresh_fields("car_emi_detail");
                        }

        });


    }
    }
});
