frappe.ui.form.on('Expense Claim', {
    start_date: function(frm) {
        console.log(frm);

        totaldays(frm);


        if(frm.doc.start_date>frm.doc.end_date){
            frappe.msgprint({
                    message:__('Start Date Should be Lesser than End Date'),
                            indicator:'red'
                    });
            frm.set_value("start_date", 0);
        }
    }
});


frappe.ui.form.on('Expense Claim', {
    end_date: function(frm) {
        console.log(frm);

        totaldays(frm);

        if(!frm.doc.start_date  && frm.doc.end_date){
            frappe.msgprint({
                    message:__('Start Date Must be valid'),
                            indicator:'red'
                    });
            frm.set_value("end_date", 0);
        }else{
        if(frm.doc.start_date>frm.doc.end_date){
            frappe.msgprint({
                    message:__('End Date Should be Greater than Start Date'),
                            indicator:'red'
                    });
            frm.set_value("end_date", 0);
        }
        }

    }
});

function totaldays(frm)
{
    if(frm.doc.start_date && frm.doc.end_date){
        cur_frm.set_value("total_days", frappe.datetime.get_day_diff(frm.doc.end_date,frm.doc.start_date));
	    cur_frm.refresh_fields("total_days");
    }
}

frappe.ui.form.on("Expense Claim", "validate", function (frm) {
    console.log(frm);

            frappe.call({
            method: "frappe.client.get_list",
                    "args": {
                        "doctype": "Expense Claim",
                        filters: { 
                            "employee": frm.doc.employee,
                            "month": frm.doc.month,
                            "year": frm.doc.year,

                            name: ["!=", frm.doc.name],
