	    cur_frm.get_field("series_list_definition").grid.cannot_add_rows = true;
	    console.log(frm);
	    if(frm.doc.allow !== undefined) 
	    {
	        frm.set_df_property("allow", "read_only", frm.is_new() ? 0 : 1);
	        frappe.call({
    			method: "spokes_tekpro_app.naming_series_manager.get_series_for_doctypeedit",
    			args: {
    			    doctype: frm.doc.allow
    			},
    			callback: function(r) {
    			    var series=cur_frm.doc.series_list_definition;
    			    cur_frm.clear_table("series_list_definition");
    			    cur_frm.refresh_fields();
    			    for(var i= 0;i<=r.message.length-1;i++)
                    {
                        var count=0;
                        var child = cur_frm.add_child('series_list_definition');
                        for(var j=0;j<=series.length-1;j++)
                        {
                            if(series[j].series_name == r.message[i])
                            {
                                count=1;
                                frappe.model.set_value(child.doctype, child.name, 'series_name',series[j].series_name);
                                frappe.model.set_value(child.doctype, child.name, 'definition',series[j].definition);
                                frappe.model.set_value(child.doctype, child.name, 'source_warehouse',series[j].source_warehouse);
                                frappe.model.set_value(child.doctype, child.name, 'target_warehouse',series[j].target_warehouse);

                            }
                        }
                        if(count===0)
                        {
                          frappe.model.set_value(child.doctype, child.name, 'series_name',r.message[i]); 
                        }
                    }
                    frm.refresh();
    			}
		    });
	    }
	}
});

