frappe.ui.form.on("Series Manager List", {
  isdefault: function(frm, cdt, cdn) 
    { 
        var onchangedata = locals[cdt][cdn];
        for(var i= 0;i<=frm.doc.series_list.length-1;i++)
        {
            if(frm.doc.series_list[i].name != onchangedata.name)
            {
                frm.doc.series_list[i].isdefault = 0;
            }
            if(frm.doc.series_list[i].ischecked === 0)
            {
                frm.doc.series_list[i].isdefault = 0;
            }
        }
        frm.refresh();
    }
});

