frappe.ui.form.on("Sales Invoice", {
    validate: function (frm) {
            console.log(frm);
            
           if (frm.is_new()) {
            let today = frappe.datetime.get_today();
            let invalid = false;

            frappe.call({
                method: "frappe.client.get_list",
                args: {
                    doctype: "Sales Invoice",
                    filters: {
                        company: frm.doc.company,
                        docstatus: 0,
                        posting_date: ["<", today]
                    },
                    fields: ["name"],
                    limit_page_length: 1
                },
                async: false, 
                callback: function(r) {
                    if (r.message && r.message.length > 0) {
                        invalid = true;
                    }
                }
