	qty: function (frm, cdt, cdn) {
        console.log(frm);
         var row = locals[cdt][cdn];
         var sd = row.qty ;
         var dd = row.item_code ;
         
              frappe.call({
                "method": "frappe.client.get",
                "args": {
                    "doctype": "Sales Order",
                    "name": row.sales_order,
                    
                } ,
                   "callback": function(rr) {
                       var aa = rr.message;
                      aa.items.forEach(function (item)
                      {
                         if(dd == item.item_code){  
                          if(sd > item.qty)
                       {
                           frappe.msgprint({
                    message:__('Quantity Should not be greater than sales order'),
                            indicator:'red'
                    });
            
                     }
                       } 
                       });
                }
	    });
        
         
	}
});

