function set_po_date_from_so(frm) {
    let so = null;

    (frm.doc.items || []).forEach(row => {
        if (row.sales_order && !so) {
            so = row.sales_order; // take first SO
        }
    });

    if (!so) return;

    frappe.db.get_value('Sales Order', so, 'po_date')
        .then(r => {
            if (r.message && r.message.po_date) {
                frm.set_value('po_date', r.message.po_date);
            }
        });
}
