function sales_order_btn(frm) {
    frm.add_custom_button(
        __("Sales Order"),
        function () {
            erpnext.utils.map_current_doc({
                method: "erpnext.selling.doctype.sales_order.sales_order.make_sales_invoice",
                source_doctype: "Sales Order",
                target: frm,
                setters: [
						{
							fieldtype: "Link",
							label: __("Customer"),
							options: "Customer",
							fieldname: "customer",
							default: frm.doc.customer,
						},
						{
						  fieldtype: "Currency",
						  label:__("Value"),
						  fieldname:"total",
						},
					],
                get_query_filters: {
                    docstatus: 1,
                    status: ["not in", ["Closed", "On Hold"]],
                    per_billed: ["<", 99.99],
                    company: frm.doc.company,
                },
            });
        },
        __("Get Item From")
    );
}
