function disable_item_link_live(frm) {

    let grid_wrapper = frm.fields_dict.items.grid.wrapper[0];

    const observer = new MutationObserver(function() {

        $(grid_wrapper)
            .find('[data-fieldname="item_code"] a')
            .each(function() {

                $(this)
                    .removeAttr('href')
                    .css({
                        'pointer-events': 'none',
                        'text-decoration': 'none',
                        'cursor': 'default'
                    });

            });

    });

    observer.observe(grid_wrapper, {
        childList: true,
        subtree: true
    });
}
function disable_salesstage_link_live(frm) {

    let grid_wrapper = frm.fields_dict.sales_stage_details.grid.wrapper[0];

    const observer = new MutationObserver(function() {

        $(grid_wrapper)
            .find('[data-fieldname="sales_stage_name"] a')
            .each(function() {

                $(this)
                    .removeAttr('href')
                    .css({
                        'pointer-events': 'none',
                        'text-decoration': 'none',
                        'cursor': 'default'
                    });

            });

    });

    observer.observe(grid_wrapper, {
        childList: true,
        subtree: true
    });
}
