function get_customer(frm){
    
    frappe.call({
            method: "frappe.client.get",
                    "args": {
                        "doctype": "Sales Person",
                        filters: { "name": frm.doc.sales_person }
                    },
                    callback: function (rr) {
                        var sinv = rr.message;
                        var emp = rr.message.employee;
                        
                        frappe.call({
            method: "frappe.client.get",
                    "args": {
                        "doctype": "Employee",
                        filters: { "name": emp }
                    },
                    callback: function (rr) {
                        var sinv = rr.message;
                        
                        
                        
                        frm.set_value("branch", rr.message.branch);
                        frm.set_value("division", rr.message.division);
                        frm.set_value("approver", rr.message.expense_approver);
                       
                    }
                    }); 
                        
                    }
                    }); 
      
        frappe.call({
                method: "spokes_tekpro_app.custom_script.get_customer_for_monthlytarget",
                args: {
                    "doc": cur_frm.doc
                },
                callback: function(r) {
                   
                    var cus =r.message;
                    cur_frm.clear_table("monthly_target");
                    for (var i = 0; i < r.message.length; i++){
                      
                    var child = cur_frm.add_child('monthly_target');
                      
                    frappe.model.set_value(child.doctype,child.name, 'customer', r.message[i].customer);
                    frappe.model.set_value(child.doctype,child.name, 'customer_name', r.message[i].customer_name);
                    frappe.model.set_value(child.doctype,child.name, 'month_1', r.message[i].month_1);
                    frappe.model.set_value(child.doctype,child.name, 'month_2', r.message[i].month_2);
                    frappe.model.set_value(child.doctype,child.name, 'month_3', r.message[i].month_3);
                    
                    cur_frm.refresh_field("monthly_target");
                    
                }
                   frappe.show_progress(__('Generating Data'), 100, 100, __('Completed!'));
                                frappe.hide_progress(); 
                    
                    }
                
            }); 


    }
    
