function fetch_rate(frm, cdt, cdn) {
    let row = locals[cdt][cdn];

    if (!row.item_code) return;

    frappe.call({
        method: "spokes_tekpro_app.custom_script.get_rate_for_salesorder",
        args: {
            customer: frm.doc.customer,
            item_code: row.item_code,
            doc_name: ""
        },
        callback: function(r) {
            if (!r.message) return;

            let sino = r.message;

            if (sino.length > 0) {
                frappe.model.set_value(cdt, cdn, "selling_rate", sino[0].rate);
            }

            frm.refresh_field("items");
        }
    });
}

