async function check_pack_size(row, cdt, cdn) {

    if (!row.item_code || !row.qty) return true;

    let r = await frappe.db.get_value('Item', row.item_code, 'custom_pack_size_qty');

    if (!r.message.custom_pack_size_qty) return true;

    let pack_size = r.message.custom_pack_size_qty;
    let entered_qty = row.qty;
    let final_qty;

    if (entered_qty <= pack_size) {
        final_qty = pack_size;
    } else if (entered_qty % pack_size !== 0) {
        final_qty = Math.ceil(entered_qty / pack_size) * pack_size;
    } else {
        return true; 
    }

    return new Promise((resolve) => {
        frappe.confirm(
            `Pack Size Qty in Item Master is ${pack_size}.
Do you want to change quantity to ${final_qty}?`,

            function () {
                frappe.model.set_value(cdt, cdn, "qty", final_qty);
                resolve(true);
            },

            function () {
                resolve(true);
            }
        );
    });
}

frappe.ui.form.on('Sales Order Item', {
    async qty(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        await check_pack_size(row, cdt, cdn);
    }
});


frappe.ui.form.on('Sales Order', {
    async validate(frm) {

        for (let row of frm.doc.items) {

            let result = await check_pack_size(row, row.doctype, row.name);

            if (!result) {
                frappe.validated = false;
                break;
            }
        }
    }
});
