function calculate_margin(frm, cdt, cdn) {
    let row = locals[cdt][cdn];

    let rate = flt(row.rate);
    let purchase_rate = flt(row.purchase_rate);

    let margin_in = 0;

    if (rate > 0) {
        // margin_in =round(((rate - purchase_rate) / rate) * 100,2);
        margin_in = flt(((rate - purchase_rate) / rate) * 100, 2);

    }
frappe.model.set_value(cdt, cdn, 'margin_in', margin_in);

    // frappe.model.set_value(
    //     cdt,
    //     cdn,
    //     'margin_in',
    //     flt(margin_in, 2)
    // );
}
frappe.ui.form.on("Sales Order", {
    validate(frm) {

        // ✅ Company bypass
        if (frm.doc.company === "TEKPRO SOLUTIONS") {
            frm.set_value("custom_price_check", 0);
            frm.set_value("custom_margin", 0);
            return;
        }

        let has_stock_item = false;
        let promises = [];

        // -------- FETCH STOCK ITEM FLAG --------
        (frm.doc.items || []).forEach(item => {
            if (!item.item_code) return;

            promises.push(
                frappe.db.get_value("Item", item.item_code, "is_stock_item")
                    .then(r => {
                        if (r?.message?.is_stock_item) {
                            has_stock_item = true;
                        }
                    })
            );
        });

        // IMPORTANT: return Promise
        return Promise.all(promises).then(() => {

            // ✅ No stock items → bypass ALL approvals
            if (!has_stock_item) {
                frm.set_value("custom_price_check", 0);
                frm.set_value("custom_margin", 0);
                return;
            }

            let priceMismatch = false;
            let lowMargin = false;

            // -------- CHECK ITEMS --------
            (frm.doc.items || []).forEach(item => {

                let selling = flt(item.selling_rate);
                let price_list = flt(item.rate);
                let margin = flt(item.margin_in);

                // 🔸 Price mismatch logic (existing)
                if (
                    selling === 0 ||
                    price_list === 0 ||
                    Math.abs(selling - price_list) > 0.001
                ) {
                    priceMismatch = true;
                }

                // 🔸 Margin logic (NEW)
                if (margin < flt(frm.doc.custom_customer_margins || 12)) {
                 lowMargin = true;
             }
          });

// if (margin < 15) 
// {
//     lowMargin = true;
//     }
//     });


            // -------- SET FLAGS --------
            frm.set_value("custom_price_check", priceMismatch ? 1 : 0);
            frm.set_value("custom_margin", lowMargin ? 1 : 0);
        });
    },

    after_save(frm) {

        if (frm.doc.company === "TEKPRO SOLUTIONS") return;

        // 🔔 Show alert ONLY if price mismatch
        if (!frm.doc.custom_price_check) return;

        let messages = [];

        frm.doc.items.forEach(item => {
            let selling = flt(item.selling_rate);
            let price_list = flt(item.rate);

            if (
                selling === 0 ||
                price_list === 0 ||
                Math.abs(selling - price_list) > 0.001
            ) {
                messages.push(
                    `Item: <b>${item.item_name || item.item_code}</b><br>` +
                    `Price List Rate: ₹${price_list.toFixed(2)}<br>` +
                    `Selling Rate: ₹${selling.toFixed(2)}`
                );
            }
        });

        if (messages.length) {
            let msg = frappe.msgprint({
                title: __("Selling Rate Mismatch"),
                message: messages.join("<hr>"),
                indicator: "orange"
            });

            setTimeout(() => {
                if (msg?.hide) msg.hide();
            }, 600000);
        }
    }
});
