frappe.ui.form.on("Purchase Order", {
    validate: function (frm) {
        // If company is TEKPRO SOLUTIONS, set price_check to 0 and skip price comparison
        if (frm.doc.company === "TEKPRO SOLUTIONS") {
            frm.set_value("price_check", 0);
            return;
        }

        let alertTriggered = false;

        $.each(frm.doc.items || [], function (i, d) {
            let amount = parseFloat(d.rate) || 0;
            let rate = parseFloat(d.rate_of_last_purchase) || 0;

            if (frm.doc.is_subcontracted === 0) {
                if (rate === 0 || amount === 0 || Math.abs(rate - amount) > 0.001) {
                    alertTriggered = true;
                }
            }
        });

        frm.set_value("price_check", alertTriggered ? 1 : 0);


    },

    after_save: function(frm) {
        // If company is TEKPRO SOLUTIONS, skip alert
        if (frm.doc.company === "TEKPRO SOLUTIONS") {
            return;
        }

        if (frm.doc.price_check === 1) {
            let messages = [];

            frm.doc.items.forEach(function(item) {
                let last = parseFloat(item.rate_of_last_purchase) || 0;
                let current = parseFloat(item.rate) || 0;

                if (last === 0 || current === 0 || Math.abs(last - current) > 0.001) {
                    messages.push(
                        `Item: <b>${item.item_name || item.item_code}</b><br>` +
                        `Last Purchase Rate: ₹${last.toFixed(2)}<br>` +
                        `Current Rate: ₹${current.toFixed(2)}`
                    );
                }
            });

            if (messages.length) {
                let msg = frappe.msgprint({
                    title: __("Price Mismatch Alert"),
                    message: messages.join("<hr>"),
                    indicator: "orange"
                });

                setTimeout(() => {
                    if (msg && msg.hide) {
                        msg.hide();
                    }
                }, 600000); // 10 minutes
            }
        }
    }
});

