frappe.ui.form.on('Purchase Order Item', {
    item_code: function (frm, cdt, cdn) {
        if(!frm.doc.creation){
        var row = locals[cdt][cdn];
        if(row.item_code){
            frappe.call({
                method: "frappe.client.get",
                "args":{
                    "doctype":"Item",
                    filters:{
                        "name": row.item_code
                    }
                },
                callback:function(rr){
                    var item = rr.message;
                    $.each(item.warehouse_, function(i,h){
                        if(h.warehouse == row.warehouse){
                            if(h.type){
                                frappe.model.set_value(row.doctype,row.name,"warehouse_type",h.type);
                            }
                        }
                    })
                }
            })
        }
        }
    }
    })
frappe.ui.form.on("Purchase Order",{
    before_submit:function(frm){
        console.log(frm);
        if(frm.doc.items){
            $.each(frm.doc.items, function(i,d){
                if(d.salesperson_master !== null && d.customer_master !== null && d.warehouse_type !== null){
                    frappe.validated = true;
                }
                else{
                    frappe.validated = false;
                    frappe.msgprint("Item" +d.item_code+" :Must be checked for Sales Person Master/Customer Master/Warehouse Type")
                }
            })
        }
    }
})    

frappe.ui.form.on('Purchase Order', {
    validate: async function(frm) {
        let disallowed_types = ['RMA', 'CCIF', 'NM', 'TRIAL', 'FOLLOW'];
        let invalid_items = [];

        for (let row of frm.doc.items) {
            if (!row.item_code) continue;

            const r = await frappe.call({
                method: "frappe.client.get",
                args: {
                    doctype: "Item",
                    name: row.item_code
                }
            });

            if (r.message) {
                let item = r.message;

                if (item.warehouse_ ) {
                    for (let wh of item.warehouse_) {
                        if (disallowed_types.includes(wh.type)) {
                            invalid_items.push({
                                item_code: row.item_code,
                                type: wh.type
                            });
                        }
                    }
                }
            }
        }

        if (invalid_items.length > 0) {
            let msg = invalid_items.map(i => 
                `Item <b>${i.item_code}</b> has disallowed warehouse type <b>${i.type}</b>`
            ).join("<br>");
            frappe.msgprint(msg);
            frappe.validated = false;
        }
    }
});

