function set_naming_series(frm) {
    const company = frm.doc.company;
    const is_return = frm.doc.is_return;

    if (company === 'ITFD PRODUCTS') {
        frm.set_value("naming_series", is_return ? "PRH.####" : "PH.####");
    } else if (company === 'SKYTEC SOLUTIONS') {
        frm.set_value("naming_series", is_return ? "PRS.####" : "PS.####");
    } else if (company === 'TEKPRO SOLUTIONS') {
        frm.set_value("naming_series", is_return ? "PRT.####" : "PT.####");
    }




    frm.refresh_field("naming_series");

}


