function total(frm, cdt, cdn) {

	var row = locals[cdt][cdn];

    if(row.current_month_quantity){  
    var tot=(row.current_month_quantity * row.stocking_factor)-(row.closing_stock + row.pending_po_quantity);
    row.to_order = tot;
    row.total = tot * row.last_purchase_rate;


    refresh_field("to_order", cdn, "table_4");
    refresh_field("total", cdn, "table_4");

    }

}





