function update(frm) {
    const dialog = new frappe.ui.Dialog({
        title: __('Update Item List'),
        fields: [
            {
                fieldtype: 'Table',
                fieldname: 'update_item_details',
                label: __('Update Item Details'),
                fields: [
                    {
                        fieldtype: 'Link',
                        fieldname: 'item_code',
                        label: __('Item Code'),
                        options: 'Item',
                        in_list_view: 1,
                        get_query: function() {
                            return {
                                filters: {
                                    'name': ['in', frm.doc.items.map(item => item.item_code)]
                                }
                            };
                        }
                    },
                    {
                        fieldtype: 'Float',
                        fieldname: 'qty',
                        label: __('Qty'),
                        in_list_view: 1
                    }
                ]
            }
        ],
        primary_action_label: __('Update'),
        primary_action: function() {
            var updated_items = dialog.get_value('update_item_details');
            updated_items.forEach(function(updated_item) {
                frm.doc.items.forEach(function(item) {
                    if (item.item_code === updated_item.item_code) {
                        frappe.model.set_value(item.doctype, item.name, 'qty', updated_item.qty);
                    }
                });
            });
            frm.refresh_field('items');
            dialog.hide();
        }
    });

    var table_data = [];
    frm.doc.items.forEach(function(item) {
        table_data.push({
            item_code: item.item_code,
            qty: item.qty
        });
    });

    dialog.fields_dict.update_item_details.df.data = table_data;
    dialog.fields_dict.update_item_details.grid.refresh();
    dialog.show();
}

