frappe.ui.form.on("Bill Of Entry Charges", {
    amount: function(frm) {
        console.log(frm);
        var total = frm.doc.total_amount_payable;
        var taxtotal = frm.doc.total_taxes;
        var tcd = frm.doc.total_customs_duty;
        var total1 = 0;
        $.each(frm.doc.bill_of_entry_charges || [], function(i, d) {
            if (d.account && d.amount) {
                total1 += flt(d.amount);
            }
        });
        var final_total = total1 + taxtotal + tcd; 
        frm.set_value("insurance_penalty", total1);
        frm.set_value("total_amount_payable", final_total);


    }

});
frappe.ui.form.on("Bill Of Entry Charges", {
   onload: function(frm) {
         console.log(frm);
        // Delay calculation by 300ms (adjust as needed)
        setTimeout(() => {
            let total_charges = 0;

            // Sum all child table amounts
            (frm.doc.bill_of_entry_charges || []).forEach(row => {
                if (row.amount && row.account) {
                    total_charges += flt(row.amount);
                }
            });

            let total_taxes = flt(frm.doc.total_taxes);
            let total_customs_duty = flt(frm.doc.total_customs_duty);

            let final_total = total_charges + total_taxes + total_customs_duty;

            // Update parent fields
            frm.set_value("insurance_penalty", total_charges);
            frm.set_value("total_amount_payable", final_total);

            // Refresh parent fields
            // frm.refresh_field("insurance_penalty");
            // frm.refresh_field("total_amount_payable");

            console.log("Updated total_amount_payable:", final_total);
        }, 300); // 300ms delay
    }
});

