frappe.ui.form.on('Material Request',{
    onload: function(frm){
        console.log(frm);
        if(!frm.doc.creation){
            cur_frm.set_value("material_request_type","Customer Provided")
            if(frm.doc.material_request_type == 'Customer Provided'){
            if(frm.doc.items){
                $.each(frm.doc.items, function(i,d) {
                    if(d.sales_order){
                        frappe.call({
                            method: "frappe.client.get",
                            "args": {
                                "doctype" : "Sales Order",
                                filters : {
                                    name : d.sales_order
                                } 
                            },
                            callback:function(rr){
                                var so = rr.message;
                                cur_frm.set_value("schedule_date",so.delivery_date)
                                cur_frm.set_value("dc_doc_no",so.po_no);
                                cur_frm.set_value("dc_doc_date",so.po_date);
                                $.each(so.items,function(i,h){
                                    if(h.item_code == d.item_code){
                                        var item = h.item_code
                                        if(item.includes("-F")){
                                            var parts = item.split('-');
                                            if (parts[parts.length - 1] === 'F') {
                                             parts[parts.length - 1] = 'R';
                                              item = parts.join('-');
                                              frappe.model.set_value(d.doctype,d.name,"item_code",item)
                                            }
                                        }
                                    }
                                })
                            }
                        })
                    }
                })
            }
            }
        }
    }
})

