frappe.ui.form.on('ADR Details', {
    price_list_rate: function(frm, cdt, cdn) {
        let child = locals[cdt][cdn];
        update_discount_request(child, frm, cdt, cdn);
    },

    distributor_net_price: function(frm, cdt, cdn) {
        let child = locals[cdt][cdn];
        update_discount_request(child, frm, cdt, cdn);
        update_distributor_margin(child, frm, cdt, cdn);
    },

    distributor_price_to_customer: function(frm, cdt, cdn) {
        let child = locals[cdt][cdn];
        update_distributor_margin(child, frm, cdt, cdn);
    }
});

function update_discount_request(child, frm, cdt, cdn) {
    if (child.price_list_rate && child.distributor_net_price) {
        let discount_request = (child.price_list_rate - child.distributor_net_price) / child.price_list_rate;
        frappe.model.set_value(cdt, cdn, 'discount_request', discount_request * 100); // Assuming percentage
    }
}

function update_distributor_margin(child, frm, cdt, cdn) {
    if (child.distributor_net_price && child.distributor_price_to_customer) {
        let distributor_margin = (child.distributor_price_to_customer - child.distributor_net_price) / child.distributor_price_to_customer;
        frappe.model.set_value(cdt, cdn, 'distributor_margin', distributor_margin * 100); // Assuming percentage
    }
}

