    item_code: function(frm, cdt, cdn) {
        fetch_adr_details(frm, cdt, cdn);
    }
});

function fetch_adr_details(frm, cdt, cdn) {
    var row = locals[cdt][cdn];

    if (!frm.doc.supplier) {
        frappe.msgprint(__('Please select a Supplier.'));
        return;
    }

    if (!frm.doc.company) {
        frappe.msgprint(__('Please select a Company.'));
        return;
    }

    if (!row.item_code) {
        frappe.msgprint(__('Please select an Item Code.'));
        return;
    }

    frappe.call({
        method: "spokes_tekpro_app.custom_script.get_adr_details",
        args: {
            supplier: frm.doc.supplier,
            item_code: row.item_code,
            company: frm.doc.company
        },
        callback: function(r) {
            if (r.message && r.message.length > 0) {
                var details = r.message[0];

                row.discount_request = details.discount_request || "";
                row.distributor_net_price = details.distributor_net_price || 0;
                row.distributor_margin = details.distributor_margin || 0;
                row.condition_applicable = details.condition_applicable || "";
                row.distributor_price_to_customer = details.distributor_price_to_customer || 0;
                row.customer = details.customer || "";

                frm.refresh_field("adr_details");
            }
        }
    });
}
