frappe.ui.form.on('Route Master', {
        onload: function(frm) {
        if (frm.is_new()) {
        
            frm.set_value('route_map_html', '');
            frm.set_value('route_coordinates', '');
            frm.fields_dict['route_map'].wrapper.innerHTML = '';
        }
    },
    
    refresh: function (frm) {
        if (frm.doc.route_coordinates && frm.doc.route_map_html) {
            frm.fields_dict['route_map'].wrapper.innerHTML = frm.doc.route_map_html;
            load_google_maps_api(() => {
                render_google_map(JSON.parse(frm.doc.route_coordinates || "[]"));
            });
        }
    },

    optimize_route_map: async function (frm) {
        load_google_maps_api(async () => {
            const coordinates = await get_all_coordinates(frm);
            if (!coordinates.start || !coordinates.end || coordinates.mids.length === 0) {
                frappe.msgprint("Please provide Start, End, and at least one Mid Location.");
                return;
            }

            const waypoints = coordinates.mids.map(mid => ({
                location: { lat: mid.lat, lng: mid.lng },
                stopover: true
            }));

            const directionsService = new google.maps.DirectionsService();
            directionsService.route({
                origin: { lat: coordinates.start.lat, lng: coordinates.start.lng },
                destination: { lat: coordinates.end.lat, lng: coordinates.end.lng },
                waypoints: waypoints,
                optimizeWaypoints: true,
                travelMode: google.maps.TravelMode.DRIVING
            }, async function (result, status) {
                if (status === google.maps.DirectionsStatus.OK) {
                    const ordered_waypoints = result.routes[0].waypoint_order.map(i => coordinates.mids[i]);

                    const full_path = [coordinates.start, ...ordered_waypoints, coordinates.end];
                    await frm.set_value('route_coordinates', JSON.stringify(full_path));
                    frm.fields_dict['route_map'].wrapper.innerHTML = `<div id="mapid" style="height: 400px;"></div>`;
                    render_google_map(full_path);
                    await frm.set_value('route_map_html', frm.fields_dict['route_map'].wrapper.innerHTML);

                    await reorder_retailers_by_coordinates(frm, ordered_waypoints);
                    await frm.save();
                } else {
                    frappe.msgprint("Could not calculate optimized route.");
                }
            });
        });
    }
});

function load_google_maps_api(callback) {
    if (typeof google !== 'undefined' && google.maps) {
        callback();
        return;
    }
    const script = document.createElement("script");
    script.src = "https://maps.googleapis.com/maps/api/js?key=AIzaSyBSRTG96aYlBH9J-4c_9xpEILfDYdGMMqg";
    script.async = true;
    script.defer = true;
    script.onload = callback;
    document.head.appendChild(script);
}

async function get_all_coordinates(frm) {
    const seen = new Set();
    const start = await get_coordinates(frm.doc.start_location);
    seen.add(frm.doc.start_location);

    const end = await get_coordinates(frm.doc.end_location);
    seen.add(frm.doc.end_location);

    const mids = [];
    for (let row of frm.doc.route_retailers) {
        if (row.location && !seen.has(row.location)) {
            const coord = await get_coordinates(row.location);
            coord.location_name = row.location;
            mids.push(coord);
            seen.add(row.location);
        }
    }

    return { start: { ...start, label: "Start" }, end: { ...end, label: "End" }, mids };
}

function render_google_map(points) {
    if (!points || points.length === 0) return;
    const map = new google.maps.Map(document.getElementById("mapid"), {
        zoom: 12,
        center: { lat: points[0].lat, lng: points[0].lng },
        mapTypeId: 'roadmap',
        streetViewControl: false,
        fullscreenControl: false,
        mapTypeControl: false,
        gestureHandling: "greedy",
    });

    const directionsService = new google.maps.DirectionsService();
    const directionsRenderer = new google.maps.DirectionsRenderer({
        map: map,
        suppressMarkers: true,
        polylineOptions: {
            strokeColor: "#00008B", 
            strokeWeight: 5,
        },
    });

    const origin = points[0];
    const destination = points[points.length - 1];
    const waypoints = points.slice(1, -1).map(p => ({
        location: { lat: p.lat, lng: p.lng },
        stopover: true,
    }));

    directionsService.route({
        origin: { lat: origin.lat, lng: origin.lng },
        destination: { lat: destination.lat, lng: destination.lng },
        waypoints: waypoints,
        optimizeWaypoints: false,
        travelMode: google.maps.TravelMode.DRIVING,
    }, function (response, status) {
        if (status === google.maps.DirectionsStatus.OK) {
            directionsRenderer.setDirections(response);
        } else {
            frappe.msgprint("Failed to draw road route on map.");
        }
    });


    points.forEach((point, index) => {
        const icon =
            index === 0
                ? "http://maps.google.com/mapfiles/ms/icons/yellow-dot.png"
                : index === points.length - 1
                    ? "http://maps.google.com/mapfiles/ms/icons/red-dot.png"
                    : "http://maps.google.com/mapfiles/ms/icons/blue-dot.png";

        new google.maps.Marker({
            position: { lat: point.lat, lng: point.lng },
            map: map,
            icon: icon,
            title: point.label || point.location_name || `Point ${index + 1}`
        });
    });
}

async function get_coordinates(location_name) {
    return frappe.call({
        method: 'route_beat_app.custom_script.get_location_coordinates',
        args: { location_name }
    }).then(res => {
        return {
            lat: res.message.latitude,
            lng: res.message.longitude
        };
    });
}

async function reorder_retailers_by_coordinates(frm, ordered_mids) {
    const map_by_location = {};
    for (let row of frm.doc.route_retailers) {
        if (row.location) map_by_location[row.location] = { ...row };
    }

    frm.clear_table('route_retailers');

    const start_location = frm.doc.start_location;
    if (start_location && map_by_location[start_location]) {
        const start_row_data = map_by_location[start_location];
        const new_start = frm.add_child('route_retailers');
        for (let key in start_row_data) {
            if (!['name', 'doctype', 'parent', 'parentfield', 'parenttype', '__unsaved'].includes(key)) {
                new_start[key] = start_row_data[key];
            }
        }
    }
    for (let mid of ordered_mids) {
        const row_data = map_by_location[mid.location_name];
        if (row_data && mid.location_name !== start_location && mid.location_name !== frm.doc.end_location) {
            const new_row = frm.add_child('route_retailers');
            for (let key in row_data) {
                if (!['name', 'doctype', 'parent', 'parentfield', 'parenttype', '__unsaved'].includes(key)) {
                    new_row[key] = row_data[key];
                }
            }
        }
    }

    const end_location = frm.doc.end_location;
    if (end_location && map_by_location[end_location]) {
        const end_row_data = map_by_location[end_location];
        const new_end = frm.add_child('route_retailers');
        for (let key in end_row_data) {
            if (!['name', 'doctype', 'parent', 'parentfield', 'parenttype', '__unsaved'].includes(key)) {
                new_end[key] = end_row_data[key];
            }
        }
    }

    await frm.refresh_field('route_retailers');
    frm.doc.route_retailers.forEach((row, index) => {
    row.idx = index + 1;
});

//await frm.save(); 
   await frm.save();
    
}

