// ==================== Load trial detail parameters ====================
function get_parameter_name(frm, callback) {
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "Trial Detail Template",
            fields: ["name1", "sno"],
            order_by: "sno"
        },
        callback(res) {
            frm.clear_table("trial_detail");
            (res.message || []).forEach(item => {
                 if (item.sno !== 19) {
        let row = frm.add_child("trial_detail");
        row.parameter_name = item.name1?.trim();
    }
            });
            frm.refresh_field("trial_detail");
            if (callback) callback();
        }
    });
}

// ==================== Load competitor tool values ====================
function get_competitor_tool(frm) {
    if (!frm.doc.opportunity) return;

    frappe.call({
        method: "frappe.client.get",
        args: {
            doctype: "Opportunity",
            name: frm.doc.opportunity
        },
        callback(r) {
            if (!r.message) return;

            let opp = r.message;

            const field_map = {
                "TOOL SUPPLIER": "current_supplier",
                "TOOL SPECIFICATION": "specification",
                "NO OF CORNER (n)": "custom_noof_corner_n",
                "NO OF POCKET (Z)": "custom_noof_pocket_z",
                "HOLDER/CUTTER SPECIFICATION": "custom_holder__cutter_specification",
                "OPERATION": "operation",
                "MATERIAL": "material",
                "UNIT PRICE": "unit_price",
                "MONTHLY VALUE": "opportunity_amount",
                "SPINDLE SPEED(RPM)": "spindle_speed_rpm",
                "CUTTING SPEED(M/MIN)": "cutting_speed",
                "FEED": "feed",
                "DEPTH OF CUT(MM)": "depth_of_cut",
                "NO. OF PASS": "noof_pass",
                "LIFE PER CORNER (In Nos)": "custom_life_per_corner",
                "CYCLE TIME (IN SECONDS)": "custom_cycle_time",
                "COST PER COMPONENT (In INR)": "custom_cost_per_component"
            };

            frm.doc.trial_detail.forEach(row => {
                let key = row.parameter_name.trim();
                if (field_map[key] && opp[field_map[key]] !== undefined) {
                    row.competitor_tool = opp[field_map[key]];
                }
            });

            frm.refresh_field("trial_detail");
            calculate_all(frm);
        }
    });
}

// ==================== CORE CALCULATIONS ====================

// Calculate all values at once
function calculate_all(frm) {
    calculate_monthly_qty(frm);
    calculate_cost_per_component(frm);
    calculate_cost_spending(frm);
}

// Helper: get relevant values from trial_detail
function get_vals(frm, field) {
    let data = {
        life: 0,
        corner: 0,
        pocket: 0,
        price: 0,
        production: Number(frm.doc.production_per_month || 0)
    };

    (frm.doc.trial_detail || []).forEach(r => {
        let v = Number(r[field] || 0);
        if (r.parameter_name === "LIFE PER CORNER (In Nos)") data.life = v;
        if (r.parameter_name === "NO OF CORNER (n)") data.corner = v;
        if (r.parameter_name === "NO OF POCKET (Z)") data.pocket = v;
        if (r.parameter_name === "UNIT PRICE") data.price = v;
    });

    return data;
}

// ---------- MONTHLY QTY ----------
function calculate_monthly_qty(frm) {
    let c = get_vals(frm, "competitor_tool");
    let o = get_vals(frm, "our_tool");

    let c_qty = 0, o_qty = 0;

    if (c.life && c.corner && c.pocket && c.production) {
        let total_life = c.life * c.corner * c.pocket;
        if (total_life > 0) c_qty = c.production / total_life;
    }

    if (o.life && o.corner && o.pocket && o.production) {
        let total_life = o.life * o.corner * o.pocket;
        if (total_life > 0) o_qty = o.production / total_life;
    }

    update_row(frm, "MONTHLY QTY(In Nos)", round(c_qty, 2), round(o_qty, 2));
}
