// ---------- COST PER COMPONENT ----------
function calculate_cost_per_component(frm) {
    let c = get_vals(frm, "competitor_tool");
    let o = get_vals(frm, "our_tool");

    let c_cost = 0, o_cost = 0;

    if (c.life && c.corner && c.pocket && c.price) {
        let total_life = c.life * c.corner * c.pocket;
        if (total_life > 0) c_cost = c.price / total_life;
    }

    if (o.life && o.corner && o.pocket && o.price) {
        let total_life = o.life * o.corner * o.pocket;
        if (total_life > 0) o_cost = o.price / total_life;
    }

    update_row(frm, "COST PER COMPONENT (In INR)", round(c_cost, 2), round(o_cost, 2));
}

// ---------- COST SPENDING / MONTH ----------
function calculate_cost_spending(frm) {
    let c = get_vals(frm, "competitor_tool");
    let o = get_vals(frm, "our_tool");

    let c_spend = 0, o_spend = 0;

    if (c.life && c.corner && c.pocket && c.price && c.production) {
        let total_life = c.life * c.corner * c.pocket;
        if (total_life > 0) c_spend = (c.production / total_life) * c.price;
    }

    if (o.life && o.corner && o.pocket && o.price && o.production) {
        let total_life = o.life * o.corner * o.pocket;
        if (total_life > 0) o_spend = (o.production / total_life) * o.price;
    }

    update_row(frm, "COST SPENDING/MONTH (In INR)", round(c_spend, 2), round(o_spend, 2));
}

// ---------- Update child table row ----------
function update_row(frm, param, comp_val, our_val) {
    (frm.doc.trial_detail || []).forEach(r => {
        if (r.parameter_name === param) {
            frappe.model.set_value(r.doctype, r.name, "competitor_tool", comp_val);
            frappe.model.set_value(r.doctype, r.name, "our_tool", our_val);
        }
    });
    frm.refresh_field("trial_detail");
}

// ---------- Rounding helper ----------
function round(val, dec) {
    return Number((val || 0).toFixed(dec));
}








































