frappe.ui.form.on("Generate Delivery Note", {
    go:function(frm) {


    if (!frm.doc.from_date || !frm.doc.to_date || !frm.doc.company) {
        frappe.msgprint("Please select From Date, To Date and Company");
        return;
    }

    frappe.call({
        method: "spokes_tekpro_app.custom_script.get_analysis_data",
        args: {
            from_date: frm.doc.from_date,
            to_date: frm.doc.to_date,
            company: frm.doc.company
        },
        freeze: true,
        callback(r) {
            if (!r.message) return;

            frm.clear_table("analysis_detail");

            r.message.forEach(row => {
                let child = frm.add_child("analysis_detail");

                child.date = row.date;
                child.sales_order = row.sales_order;
                child.item_code = row.item_code;
                child.customer = row.customer;
                child.customer_name = row.customer_name;
                child.description = row.description;
                child.qty = row.qty;
                child.pending_qty = row.pendingqty;
                child.allocate_qty = row.pendingqty;
                child.billed_qty = row.billed_qty;
                child.qty_to_bill = row.qty_to_bill;
                child.current_stock = row.current_stock;
                child.delivery_date = row.delivery_date;
                child.billing_status = row.billing_status;
                child.credit_lock = row.credit_lock;
                child.dispatch_instructions = row.dispatch_instructions;
                child.warehouse = row.warehouse;
                child.so_detail = row.so_name;
                child.reserved_stock = row.reserved_stock;
            });
            cur_frm.save();
            frm.refresh_field("analysis_detail");
        }
    });
}
});
window.printPickList = function(docname) {

    const data = {
        'printformats': [
            {
                'name': 'Generate Delivery Note',
                'printformat': 'Generate Delivery Note',
                'idx': 1,
                '__checked': 1
            }
        ]
    };

    const json_string = JSON.stringify(data.printformats);

    const w = window.open(
        '/api/method/spokes_tekpro_app.print_format.download_multi_pdf?' +
        'doctype=' + encodeURIComponent('Generate Delivery Note') +
        '&name=' + encodeURIComponent(docname) +
        '&count=1' +   
        '&format=' + encodeURIComponent(json_string) +
        '&no_letterhead=0'
    );

    if (!w) {
        frappe.msgprint('Please enable pop-ups');
    }
};


frappe.ui.form.on('Generate Delivery Note', {

    refresh(frm) {
        // if (!frm.doc.islocal) {
        //     frm.add_custom_button(__("Pick List"), function () {
        //         window.printPickList(frm.doc.name);
        //     });
        // }
    },

    generate_dn: function(frm) {

        if (frm.is_dirty()) {
            frappe.msgprint("Please Save the Document First");
            return;
        }

        frappe.call({
            method: 'spokes_tekpro_app.custom_script.generate_delivery_notes',
            args: {
                docname: frm.doc.name
            },
            freeze: true,

            callback: function (r) {

                if (Array.isArray(r.message) && r.message.length > 0) {

                    let names_json = encodeURIComponent(JSON.stringify(r.message));

                    let multi_print_link =
                        `/api/method/frappe.utils.print_format.download_multi_pdf` +
                        `?doctype=${encodeURIComponent("Delivery Note")}` +
                        `&name=${names_json}` +
                        `&format=${encodeURIComponent("Delivery Note")}` +
                        `&no_letterhead=1` +
                        `&letterhead=${encodeURIComponent("No Letterhead")}`;

                    let dn_list_html = r.message.map(dn =>
                        `<li>
                            <a href="/app/delivery-note/${dn}" target="_blank">${dn}</a>
                        </li>`
                    ).join("");

                    frappe.msgprint({
                        title: "Delivery Notes Created",
                        message: `
                            <p><b>Delivery Notes:</b></p>
                            <ul>${dn_list_html}</ul>

                            <br>

                            <button class="btn btn-primary" id="print_dn_btn">
                                Print Delivery Note
                            </button>

                            <button class="btn btn-secondary" id="print_pick_btn" style="margin-left:10px;">
                                Print Pick List
                            </button>
                        `,
                        wide: true
                    });

          
                    setTimeout(() => {

                        document.getElementById("print_dn_btn").onclick = function () {
                            window.open(multi_print_link, "_blank");
                               frm.clear_table("analysis_detail");
        frm.refresh_field("analysis_detail"); // safe here
        frm.save();
                        };

                        document.getElementById("print_pick_btn").onclick = function () {
                            window.printPickList(frm.doc.name);
                        };

                    }, 300);
                    
                      frm.clear_table("analysis_detail");
    //frm.refresh_field("analysis_detail");
    frm.save();

                } else {
                    frappe.msgprint("No Delivery Note Created. Items may already be delivered.");
                }
            }
        });
    }
});

